import{_ as o,H as a,f as e,i as n}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"Claude Code 总览与心智","description":"","frontmatter":{},"headers":[],"relativePath":"../claudeLearning/01-Claude-Code总览与心智.md","filePath":"../claudeLearning/01-Claude-Code总览与心智.md","lastUpdated":1778496697000}'),s={name:"../claudeLearning/01-Claude-Code总览与心智.md"};function d(r,t,l,i,u,p){return a(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="claude-code-总览与心智" tabindex="-1">Claude Code 总览与心智 <a class="header-anchor" href="#claude-code-总览与心智" aria-label="Permalink to &quot;Claude Code 总览与心智&quot;">​</a></h1><p>aiLearning/38 里讲过 Coding Agent 的通用骨架:<strong>主循环 + 文件/终端工具 + 模型</strong>。Claude Code 就是这个骨架 Anthropic 自己亲手做出来的版本。和 Cursor、Cline、Aider 比起来,它有一个独特定位——<strong>不是 IDE 插件,而是一个跑在终端里的 CLI</strong>。这件事看起来不起眼,但它决定了 Claude Code 后面所有的设计走向。</p><blockquote><p>一句话先记住:<strong>Cursor 是给 Claude / GPT 套了个编辑器壳;Claude Code 是把编辑器去掉,只留下 Agent 内核</strong>。前者帮你写代码,后者直接帮你&quot;完成一件事&quot;——可能涉及编辑代码,但同样可能是审 PR、跑实验、写文档、改配置。</p></blockquote><hr><h2 id="一、为什么是终端-不是-ide" tabindex="-1">一、为什么是终端,不是 IDE <a class="header-anchor" href="#一、为什么是终端-不是-ide" aria-label="Permalink to &quot;一、为什么是终端,不是 IDE&quot;">​</a></h2><p>写 Claude Code 的核心设计选择只有一个:<strong>终端原生</strong>。这件事的好处分三层。</p><h3 id="_1-1-终端是程序员的-操作系统接口" tabindex="-1">1.1 终端是程序员的&quot;操作系统接口&quot; <a class="header-anchor" href="#_1-1-终端是程序员的-操作系统接口" aria-label="Permalink to &quot;1.1 终端是程序员的&quot;操作系统接口&quot;&quot;">​</a></h3><p>IDE 里能干的事 ≈ 编辑代码 + 跑命令。终端能干的事 = 整台电脑能干的事。Claude Code 跑在终端,意味着它可以:</p><ul><li>跑任何 CLI(<code>gh</code>、<code>docker</code>、<code>kubectl</code>、<code>psql</code>、<code>bun test</code>……)</li><li>用任何 shell 工具(<code>grep</code>、<code>awk</code>、<code>jq</code>、<code>fd</code>)</li><li>调任何 API、写任何文件、起任何后台进程</li></ul><p><strong>Cursor 想做这些必须给自己的 IDE 加功能</strong>;Claude Code 不需要——它已经在最强的&quot;功能集合&quot;里了。</p><h3 id="_1-2-可脚本化、可-ci-化" tabindex="-1">1.2 可脚本化、可 CI 化 <a class="header-anchor" href="#_1-2-可脚本化、可-ci-化" aria-label="Permalink to &quot;1.2 可脚本化、可 CI 化&quot;">​</a></h3><p><code>claude -p &quot;review this PR&quot;</code> 直接当命令用;CI 里可以跑 Claude 做自动化任务;远程 SSH 进服务器跑也行。<strong>它不依赖 GUI</strong>——这让它能进入所有&quot;非交互式开发&quot;场景:CI、远程机器、生产环境调试、批量任务。</p><blockquote><p>Cursor 没法在 GitHub Actions 里跑;Claude Code 可以。这是定位差异,不是优劣差异。</p></blockquote><h3 id="_1-3-工具回归本质-文件读-写-搜-跑命令" tabindex="-1">1.3 工具回归本质:文件读/写/搜 + 跑命令 <a class="header-anchor" href="#_1-3-工具回归本质-文件读-写-搜-跑命令" aria-label="Permalink to &quot;1.3 工具回归本质:文件读/写/搜 + 跑命令&quot;">​</a></h3><p>Coding Agent 的灵魂工具就那几个:<code>Read</code> / <code>Edit</code> / <code>Write</code> / <code>Bash</code> / <code>Glob</code> / <code>Grep</code>。Claude Code 不打算在这之外发明新的 IDE 概念——它认为<strong>终端 + 文件 + 命令</strong>已经足够表达&quot;程序员要干的所有事&quot;。</p><hr><h2 id="二、和同类产品的横向对比" tabindex="-1">二、和同类产品的横向对比 <a class="header-anchor" href="#二、和同类产品的横向对比" aria-label="Permalink to &quot;二、和同类产品的横向对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>形态</th><th>主战场</th><th>心智模型</th></tr></thead><tbody><tr><td><strong>Cursor</strong></td><td>IDE(VSCode fork)</td><td>写代码、补全、内联编辑</td><td>&quot;AI 增强的 VSCode&quot;</td></tr><tr><td><strong>Cline</strong></td><td>VSCode 插件</td><td>透明 Agent,看每步</td><td>&quot;可视化的 Claude Code&quot;</td></tr><tr><td><strong>Aider</strong></td><td>终端 CLI</td><td>整文件改写、git 集成</td><td>&quot;git-native 的 pair programmer&quot;</td></tr><tr><td><strong>Devin</strong></td><td>Web 平台</td><td>长任务、自治</td><td>&quot;你下达任务我去做&quot;</td></tr><tr><td><strong>Claude Code</strong></td><td>终端 CLI</td><td>任何能用终端表达的事</td><td>&quot;通用 Coding Agent,可脚本化&quot;</td></tr><tr><td><strong>Codex CLI</strong>(OpenAI)</td><td>终端 CLI</td><td>Claude Code 同形态</td><td>OpenAI 阵营对位产品</td></tr></tbody></table><p><strong>关键差别</strong>:Cursor 把 LLM 嵌进编辑器;Claude Code 把编辑器拆掉,只留 LLM + 工具 + 终端。<strong>前者强在交互,后者强在自动化与扩展性</strong>。</p><blockquote><p>这两条路径会持续共存。<strong>写代码用 Cursor、做事用 Claude Code</strong> 是最常见的组合。</p></blockquote><hr><h2 id="三、claude-code-的五大可扩展层" tabindex="-1">三、Claude Code 的五大可扩展层 <a class="header-anchor" href="#三、claude-code-的五大可扩展层" aria-label="Permalink to &quot;三、Claude Code 的五大可扩展层&quot;">​</a></h2><p>终端 CLI 听上去简单,但 Claude Code 真正强大的地方是它的<strong>扩展面</strong>。理解这五层,你就掌握了整个生态:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 1. Slash Commands  (你定义的快捷指令)        │</span></span>
<span class="line"><span>│ 2. Hooks           (生命周期钩子,自动化)    │</span></span>
<span class="line"><span>│ 3. MCP             (外接工具协议)           │</span></span>
<span class="line"><span>│ 4. Subagents       (任务分包给子 Agent)     │</span></span>
<span class="line"><span>│ 5. Skills          (按需加载的专业知识)      │</span></span>
<span class="line"><span>└────────────────────────────────────────────┘</span></span>
<span class="line"><span>              ↑</span></span>
<span class="line"><span>        Claude Code 内核</span></span>
<span class="line"><span>   (主循环 + 工具 + 权限 + 上下文管理)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>层</th><th>干什么</th><th>谁触发</th><th>例子</th></tr></thead><tbody><tr><td><strong>Slash Commands</strong></td><td>把常用 prompt 模板化</td><td>用户输 <code>/xxx</code></td><td><code>/review</code>、<code>/security-review</code>、<code>/init</code></td></tr><tr><td><strong>Hooks</strong></td><td>在生命周期事件上跑脚本</td><td>Claude Code 自动触发</td><td>tool 调用前/后、对话结束、文件被改</td></tr><tr><td><strong>MCP</strong></td><td>外接工具(数据库、内部 API、第三方)</td><td>LLM 调用</td><td>Notion / Slack / 内部部署平台</td></tr><tr><td><strong>Subagents</strong></td><td>分包子任务到独立上下文</td><td>LLM 主动派发</td><td>探索代码、做 review、跑研究</td></tr><tr><td><strong>Skills</strong></td><td>按需加载的专业知识包</td><td>LLM 按描述匹配触发</td><td>&quot;审 PR&quot;、&quot;做安全审计&quot;、&quot;配 settings&quot;</td></tr></tbody></table><p><strong>这五层不是平级的,各有各的应用场景</strong>(后面每一层都有专门的篇章)。但你要先知道它们的存在和分工,后面具体技术才不会混在一起。</p><blockquote><p>第一次用 Claude Code 容易陷入&quot;什么都用 slash command 解决&quot;或&quot;什么都用 hook 解决&quot;。<strong>正确的方式是按&quot;谁触发&quot;来选层</strong>——用户每次手动触发用 slash;按事件自动触发用 hook;按语义匹配触发用 skill;独立子任务用 subagent;外接系统用 MCP。</p></blockquote><hr><h2 id="四、和-chatgpt-普通-llm-用法的心智差别" tabindex="-1">四、和 ChatGPT / 普通 LLM 用法的心智差别 <a class="header-anchor" href="#四、和-chatgpt-普通-llm-用法的心智差别" aria-label="Permalink to &quot;四、和 ChatGPT / 普通 LLM 用法的心智差别&quot;">​</a></h2><p>很多人第一次用 Claude Code,带着用 ChatGPT 的习惯——&quot;我问你一个问题,你回答我&quot;。这是错的。</p><p>Claude Code 的正确用法是<strong>告诉它你要完成的目标,而不是问它问题</strong>:</p><table tabindex="0"><thead><tr><th>不好的用法</th><th>好的用法</th></tr></thead><tbody><tr><td>&quot;怎么改这个 bug?&quot;</td><td>&quot;把这个 bug 修了,跑测试通过&quot;</td></tr><tr><td>&quot;这段代码什么意思?&quot;</td><td>&quot;把这段代码加注释解释清楚&quot;</td></tr><tr><td>&quot;我的部署有问题&quot;</td><td>&quot;排查一下生产环境为什么 502,看 nginx 日志和最近的 commit&quot;</td></tr><tr><td>&quot;Redis 怎么配?&quot;</td><td>&quot;把项目接入 Redis,用 ioredis,配置走 env&quot;</td></tr></tbody></table><p><strong>关键转变</strong>:你在和一个<strong>会动手的同事</strong>对话,不是和一个百科全书对话。Claude Code 会:</p><ol><li>读相关文件,理解上下文</li><li>制定计划(简单的省略、复杂的进 plan mode)</li><li>执行(改文件、跑命令、调 MCP)</li><li>验证(跑测试、跑 lint、读输出)</li><li>必要时迭代</li></ol><p><strong>你的角色从&quot;提问者&quot;变成&quot;项目负责人&quot;</strong>。</p><blockquote><p>这个心智转变是用好 Claude Code 的最大门槛。<strong>很多人用了几个月仍然在&quot;问问题&quot;,而没有&quot;派任务&quot;</strong>——多半因为不信任、或没耐心审 diff。这两件事都会随着用得越多越自然。</p></blockquote><hr><h2 id="五、什么场景该用-什么场景不该" tabindex="-1">五、什么场景该用,什么场景不该 <a class="header-anchor" href="#五、什么场景该用-什么场景不该" aria-label="Permalink to &quot;五、什么场景该用,什么场景不该&quot;">​</a></h2><h3 id="该用" tabindex="-1">该用 <a class="header-anchor" href="#该用" aria-label="Permalink to &quot;该用&quot;">​</a></h3><ul><li><strong>重复性写代码</strong>:CRUD、表单、基础组件、配置文件、迁移脚本</li><li><strong>跨文件改造</strong>:重命名一个 API、把一个 hook 升级一个版本、统一 lint 风格</li><li><strong>不熟悉的领域</strong>:第一次接 Stripe、第一次写 Flutter、第一次配 K8s</li><li><strong>调试</strong>:让它跑命令、看日志、定位问题</li><li><strong>审 PR / 写文档 / 写测试</strong>:这是它最擅长的&quot;低创造性 + 高重复&quot;工作</li><li><strong>跨工具串联</strong>:从 GitHub issue → 写代码 → 起 PR → 写描述 → 跑测试</li></ul><h3 id="不该用" tabindex="-1">不该用 <a class="header-anchor" href="#不该用" aria-label="Permalink to &quot;不该用&quot;">​</a></h3><ul><li><strong>极小的改动</strong>:改一个 typo、加一行 log,自己改更快</li><li><strong>核心架构决策</strong>:让它给意见可以,但<strong>最终决定必须你自己拍</strong></li><li><strong>你完全不懂的代码</strong>:Claude Code 写出来的代码你看不懂 = 你失去对系统的控制权;<strong>先自己读懂再用 AI 改</strong></li><li><strong>创造性写作</strong>:文学性、情感性的输出 LLM 都很弱,Coding Agent 更甚</li><li><strong>需要严格保密的代码</strong>:走 API 就意味着代码出网,<strong>敏感系统按公司合规策略来</strong></li></ul><blockquote><p>一条硬规则:<strong>你看不懂的 PR 不要 merge</strong>。Claude Code 帮你写得快,但<strong>评审责任永远在你</strong>——这一点别因为它写得&quot;看起来对&quot;就放松。</p></blockquote><hr><h2 id="六、本系列的整体地图" tabindex="-1">六、本系列的整体地图 <a class="header-anchor" href="#六、本系列的整体地图" aria-label="Permalink to &quot;六、本系列的整体地图&quot;">​</a></h2><p>知道了 Claude Code 是什么,本系列后续 29 篇大致这样组织:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01     总览(这篇)</span></span>
<span class="line"><span>02-11  Claude Code 工作流:配置 → 工具 → 五大扩展层 → 集成</span></span>
<span class="line"><span>       这一段是&quot;会用 Claude Code&quot;的全部内容,优先级最高</span></span>
<span class="line"><span></span></span>
<span class="line"><span>12-18  Anthropic API:把 Claude 当能力组件用</span></span>
<span class="line"><span>       这一段是&quot;自己写应用&quot;的基础,绕不开</span></span>
<span class="line"><span></span></span>
<span class="line"><span>19-23  Claude Agent SDK:写自己的 Coding Agent</span></span>
<span class="line"><span>       Anthropic 把 Claude Code 内核开源出来给你用,这一段教你拼</span></span>
<span class="line"><span></span></span>
<span class="line"><span>24-27  MCP Server 开发:写自己的工具</span></span>
<span class="line"><span>       AI 系列只讲了协议,这里讲&quot;我要写一个 server 给团队用&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>28-30  设计模式 + 生产化</span></span>
<span class="line"><span>       前面所有概念串起来,讲选型、调试、团队协作</span></span></code></pre></div><p><strong>优先级</strong>:11 之前每一篇都建议看;12-18 看你要不要写应用;19 之后是工程化路径,按需。</p><hr><h2 id="七、给新手的最快入门路径" tabindex="-1">七、给新手的最快入门路径 <a class="header-anchor" href="#七、给新手的最快入门路径" aria-label="Permalink to &quot;七、给新手的最快入门路径&quot;">​</a></h2><p>如果你是第一次用,不要从 README 啃起,按这个路径走:</p><ol><li><strong>装上,跑通</strong>:<code>npm install -g @anthropic-ai/claude-code</code>,在一个真实项目里输 <code>claude</code></li><li><strong>派一个真任务</strong>:别问&quot;你能干什么&quot;,直接说&quot;把 README 翻译成中文&quot;或&quot;给这个项目加一个 Dockerfile&quot;</li><li><strong>看它怎么干</strong>:观察它读哪些文件、调哪些工具、决策依据是什么</li><li><strong>学会打断</strong>:<code>Esc</code> 中断、<code>Ctrl+C</code> 退出、<code>/clear</code> 清上下文</li><li><strong>第二周开始定制</strong>:写第一个 slash command、加第一个 hook、配一个 MCP</li></ol><p><strong>第一个月别急着看完所有文档,边用边补</strong>。Claude Code 的功能矩阵很大,但 80% 的日常用法只用到 20%。</p><blockquote><p>真正的学习曲线在&quot;派任务的能力&quot;——会拆任务、会写好的指令、知道它哪里靠谱哪里不靠谱。<strong>这部分是经验,不是知识</strong>。</p></blockquote><hr><h2 id="八、踩坑提醒-总览版-后面每篇细讲" tabindex="-1">八、踩坑提醒(总览版,后面每篇细讲) <a class="header-anchor" href="#八、踩坑提醒-总览版-后面每篇细讲" aria-label="Permalink to &quot;八、踩坑提醒(总览版,后面每篇细讲)&quot;">​</a></h2><ol><li><strong>不读 diff 直接 yes</strong>——最常见、最危险的错误。Claude Code 让确认变成习惯之后,你会越来越懒得读 diff,然后某天它把你的 schema 删了</li><li><strong>不用 plan mode 就让它做大改动</strong>——大改一定先 plan,再执行;别把 plan mode 当多余步骤</li><li><strong>CLAUDE.md 没写或乱写</strong>——项目里没有 CLAUDE.md = 每次新会话都从零理解项目,效率减半</li><li><strong>MCP server 一接一大堆</strong>——server 越多,工具列表越长,LLM 选错的概率越大;<strong>只接当前需要的</strong></li><li><strong>slash command 写得太具体</strong>——一次只用一次的指令不必做成 slash;<strong>真正反复用的才值得</strong></li><li><strong>没设 permissions</strong>——默认权限可能太宽或太窄,<strong>用一周后该 audit 一次 settings</strong></li><li><strong>不知道有 hook</strong>——重复的&quot;每次 commit 前要做 X&quot;不是给 Claude 念三遍,是写一个 hook</li><li><strong>当成 ChatGPT 用</strong>——你给它&quot;问题&quot;,它给你&quot;答案&quot;,但<strong>你的目标是让它&quot;做事&quot;</strong></li><li><strong>完全信任输出</strong>——LLM 永远会幻觉,<strong>重要文件改完一定看 git diff</strong></li><li><strong>不学快捷键</strong>——Tab、Esc、Ctrl+R(transcript)、<code>/clear</code>、<code>/compact</code>,这几个不学每天损失 10 分钟</li></ol><hr><p>下一篇:<code>02-安装配置与settings.md</code>,讲 settings.json 的三层结构(user / project / local)、env、model 选择,以及为什么团队协作时这三层的边界很重要。</p>`,59)])])}const h=o(s,[["render",d]]);export{g as __pageData,h as default};
